final:
module RefModule(
    clk,
    Load,
    not_reset,
    D,
    Q
);input wire clk;
input wire not_reset;
input wire Load;
input wire [15:0] D;
output wire [15:0] Q;

reg [15:0] unused_Q_ALTERA_SYNTHESIZED;

always @(posedge clk or negedge not_reset) begin
    if (!not_reset) begin
        unused_Q_ALTERA_SYNTHESIZED <= 0;
    end else if (Load) begin
        unused_Q_ALTERA_SYNTHESIZED <= D;
    end
end

assign Q = unused_Q_ALTERA_SYNTHESIZED;

endmodule
